-- =============================================================================
-- SNOMED CT / Terminology API - PostgreSQL DDL
-- 변환 출처: MySQLDDL.sql (MySQL InnoDB) → PostgreSQL 18 호환
--
-- 주요 변환 규칙:
--   bigint(20) AUTO_INCREMENT → BIGINT GENERATED BY DEFAULT AS IDENTITY
--   int(11) AUTO_INCREMENT    → INTEGER GENERATED BY DEFAULT AS IDENTITY
--   tinyint(1/4)              → SMALLINT  (MySQL 1-byte boolean 대체)
--   int(11)                   → INTEGER
--   datetime                  → TIMESTAMP
--   ENGINE=InnoDB CHARSET=utf8 → 제거
--   KEY idx (col)             → 테이블 정의 분리 후 CREATE INDEX
--   UNIQUE KEY                → UNIQUE 제약 또는 CREATE UNIQUE INDEX
--   # 주석                    → -- 주석
-- =============================================================================

-- 스키마 초기화: 기존 term 스키마 전체 삭제 후 재생성
DROP SCHEMA IF EXISTS term CASCADE;
CREATE SCHEMA term;
SET search_path TO term;

-- pg_trgm: 유사도·접두어 검색(SEARCH_INDEX)에 필요
CREATE EXTENSION IF NOT EXISTS pg_trgm;

-- -----------------------------------------------------------------------------
-- CONCEPT
-- SNOMED CT 개념의 전체 이력(Full release) 저장 테이블
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS CONCEPT;
CREATE TABLE CONCEPT (
    SEQ               BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    CONCEPT_ID        VARCHAR(18)  NOT NULL,
    EFFECTIVE_TIME    CHAR(8)      NOT NULL,
    -- MySQL tinyint(1) active 플래그를 SMALLINT로 매핑 (0=비활성, 1=활성)
    ACTIVE            SMALLINT     NOT NULL,
    MODULE_ID         VARCHAR(18)  NOT NULL,
    DEFINITION_STATUS_ID CHAR(18)  NOT NULL,
    DATE_CREATED      CHAR(8)      DEFAULT NULL,
    PRIMARY KEY (SEQ)
);

CREATE INDEX IDX_CONCEPT_CONCEPT         ON CONCEPT (CONCEPT_ID);
CREATE INDEX IDX_CONCEPT_CONCEPT_ETIME   ON CONCEPT (CONCEPT_ID, EFFECTIVE_TIME);
CREATE INDEX IDX_CONCEPT_ETIME           ON CONCEPT (EFFECTIVE_TIME);
CREATE INDEX IDX_CONCEPT_DS_ID           ON CONCEPT (DEFINITION_STATUS_ID);
CREATE INDEX IDX_CONCEPT_MOD_ID          ON CONCEPT (MODULE_ID);
CREATE INDEX IDX_CONCEPT_ACT             ON CONCEPT (ACTIVE);

-- -----------------------------------------------------------------------------
-- DESCRIPTION
-- 영어 기반 전체 이력 설명(Description) 저장 테이블
-- 국제 RF2 Full release의 sct2_Description_Full-en 파일을 적재
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS DESCRIPTION;
CREATE TABLE DESCRIPTION (
    SEQ               BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    DESCRIPTION_ID    VARCHAR(18)  NOT NULL,
    EFFECTIVE_TIME    CHAR(8)      NOT NULL,
    ACTIVE            SMALLINT     NOT NULL,
    MODULE_ID         VARCHAR(18)  NOT NULL,
    CONCEPT_ID        VARCHAR(18)  NOT NULL,
    LANGUAGE_CODE     CHAR(2)      NOT NULL,
    TYPE_ID           CHAR(18)     NOT NULL,
    TERM              VARCHAR(4096) NOT NULL,
    CASE_SIGNIFICANCE_ID CHAR(18)  NOT NULL,
    DATE_CREATED      CHAR(8)      DEFAULT NULL,
    PRIMARY KEY (SEQ)
);

CREATE INDEX IDX_DESCRIPTION_C_ID_T_ID_ETIME ON DESCRIPTION (CONCEPT_ID, TYPE_ID, EFFECTIVE_TIME);
CREATE INDEX IDX_DESCRIPTION_T_ID_ETIME      ON DESCRIPTION (TYPE_ID, EFFECTIVE_TIME);
CREATE INDEX IDX_DESCRIPTION_C_ID            ON DESCRIPTION (CONCEPT_ID);
CREATE INDEX IDX_DESCRIPTION_C_ID_ETIME      ON DESCRIPTION (CONCEPT_ID, EFFECTIVE_TIME);
CREATE INDEX IDX_DESCRIPTION_D_ID            ON DESCRIPTION (DESCRIPTION_ID);
CREATE INDEX IDX_DESCRIPTION_ETIME           ON DESCRIPTION (EFFECTIVE_TIME);
CREATE INDEX IDX_DESCRIPTION_ACTIVE          ON DESCRIPTION (ACTIVE);
CREATE INDEX IDX_DESCRIPTION_M_ID            ON DESCRIPTION (MODULE_ID);
CREATE INDEX IDX_DESCRIPTION_L_CODE          ON DESCRIPTION (LANGUAGE_CODE);
CREATE INDEX IDX_DESCRIPTION_T_ID            ON DESCRIPTION (TYPE_ID);

-- -----------------------------------------------------------------------------
-- DESCRIPTION_TP
-- 다국어(Translation Package) 설명 저장 테이블
-- LANGUAGE_CULTURE 컬럼으로 국가별 언어팩 구분 (예: ko-KR, en-US)
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS DESCRIPTION_TP;
CREATE TABLE DESCRIPTION_TP (
    -- int(11) AUTO_INCREMENT: 국제 설명 수가 bigint 불필요 수준이므로 INTEGER 사용
    SEQ               INTEGER GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    DESCRIPTION_ID    VARCHAR(18)  NOT NULL,
    EFFECTIVE_TIME    CHAR(8)      NOT NULL,
    ACTIVE            SMALLINT     NOT NULL,
    MODULE_ID         VARCHAR(18)  NOT NULL,
    CONCEPT_ID        VARCHAR(18)  NOT NULL,
    LANGUAGE_CODE     CHAR(2)      NOT NULL,
    LANGUAGE_CULTURE  CHAR(5)      DEFAULT NULL,
    -- TYPE_ID: 900000000000003001=FSN, 900000000000548007=Preferred, 900000000000013009=Synonym
    TYPE_ID           VARCHAR(18)  NOT NULL,
    TERM              VARCHAR(4096) NOT NULL,
    -- CASE_SIGNIFICANCE_ID: 900000000000448009=CI, 900000000000017005=CS, 900000000000020002=Initial-CI
    CASE_SIGNIFICANCE_ID VARCHAR(18) NOT NULL,
    DATE_CREATED      CHAR(8)      DEFAULT NULL,
    PRIMARY KEY (SEQ)
);

-- -----------------------------------------------------------------------------
-- INFERRED_RELATIONSHIP
-- IS-A 및 속성 관계의 전체 이력(Full release) 저장 테이블
-- Classifier가 추론(infer)한 관계만 포함
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS INFERRED_RELATIONSHIP;
CREATE TABLE INFERRED_RELATIONSHIP (
    SEQ               BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    RELATIONSHIP_ID   VARCHAR(18)  NOT NULL,
    EFFECTIVE_TIME    CHAR(8)      NOT NULL,
    ACTIVE            SMALLINT     NOT NULL,
    MODULE_ID         VARCHAR(18)  NOT NULL,
    SOURCE_ID         VARCHAR(18)  NOT NULL,
    DESTINATION_ID    VARCHAR(18)  NOT NULL,
    RELATIONSHIP_GROUP INTEGER     NOT NULL,
    TYPE_ID           VARCHAR(18)  NOT NULL,
    CHARACTERISTIC_TYPE_ID CHAR(18) NOT NULL,
    MODIFIER_ID       VARCHAR(18)  NOT NULL,
    DATE_CREATED      CHAR(8)      DEFAULT NULL,
    PRIMARY KEY (SEQ)
);

CREATE INDEX IDX_INFERRED_S_ID         ON INFERRED_RELATIONSHIP (SOURCE_ID);
CREATE INDEX IDX_INFERRED_ETIME_S_ID   ON INFERRED_RELATIONSHIP (EFFECTIVE_TIME, SOURCE_ID);
CREATE INDEX IDX_INFERRED__S_ID_ETIME  ON INFERRED_RELATIONSHIP (SOURCE_ID, EFFECTIVE_TIME);

-- -----------------------------------------------------------------------------
-- INFERRED_RELATIONSHIP_SNAP
-- IS-A 및 속성 관계의 스냅샷(Snapshot release) 저장 테이블
-- 최신 상태의 관계만 보관하여 빠른 조회에 사용
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS INFERRED_RELATIONSHIP_SNAP;
CREATE TABLE INFERRED_RELATIONSHIP_SNAP (
    SEQ               BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    RELATIONSHIP_ID   VARCHAR(18)  NOT NULL,
    EFFECTIVE_TIME    CHAR(8)      NOT NULL,
    ACTIVE            SMALLINT     NOT NULL,
    MODULE_ID         VARCHAR(18)  NOT NULL,
    SOURCE_ID         VARCHAR(18)  NOT NULL,
    DESTINATION_ID    VARCHAR(18)  NOT NULL,
    RELATIONSHIP_GROUP INTEGER     NOT NULL,
    TYPE_ID           VARCHAR(18)  NOT NULL,
    CHARACTERISTIC_TYPE_ID CHAR(18) NOT NULL,
    MODIFIER_ID       VARCHAR(18)  NOT NULL,
    DATE_CREATED      CHAR(8)      DEFAULT NULL,
    PRIMARY KEY (SEQ)
);

CREATE INDEX IDX_INFERRED_SNAP_S_ID        ON INFERRED_RELATIONSHIP_SNAP (SOURCE_ID);
CREATE INDEX IDX_INFERRED_SNAP_ETIME_S_ID  ON INFERRED_RELATIONSHIP_SNAP (EFFECTIVE_TIME, SOURCE_ID);

-- -----------------------------------------------------------------------------
-- STATED_RELATIONSHIP
-- 저자가 명시적으로 작성한 관계의 전체 이력 저장 테이블
-- Classifier 추론 전 원본 관계(IS-A, attribute) 포함
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS STATED_RELATIONSHIP;
CREATE TABLE STATED_RELATIONSHIP (
    SEQ               BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    RELATIONSHIP_ID   VARCHAR(18)  NOT NULL,
    EFFECTIVE_TIME    CHAR(8)      NOT NULL,
    ACTIVE            SMALLINT     NOT NULL,
    MODULE_ID         VARCHAR(18)  NOT NULL,
    SOURCE_ID         VARCHAR(18)  NOT NULL,
    DESTINATION_ID    VARCHAR(18)  NOT NULL,
    RELATIONSHIP_GROUP INTEGER     NOT NULL,
    TYPE_ID           VARCHAR(18)  NOT NULL,
    CHARACTERISTIC_TYPE_ID CHAR(18) NOT NULL,
    MODIFIER_ID       VARCHAR(18)  NOT NULL,
    PRIMARY KEY (SEQ)
);

CREATE INDEX IDX_STATED_S_ID         ON STATED_RELATIONSHIP (SOURCE_ID);
CREATE INDEX IDX_STATED_ETIME_S_ID   ON STATED_RELATIONSHIP (EFFECTIVE_TIME, SOURCE_ID);
CREATE INDEX IDX_STATED_S_ID_ETIME   ON STATED_RELATIONSHIP (SOURCE_ID, EFFECTIVE_TIME);

-- -----------------------------------------------------------------------------
-- MRCM_CONSTRAINTS
-- SNOMED CT Machine Readable Concept Model(MRCM) 속성 도메인/범위 제약 조건
-- REFERENCESET에서 파생한 비정규화 조회용 테이블 (importer 전처리 결과)
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS MRCM_CONSTRAINTS;
CREATE TABLE MRCM_CONSTRAINTS (
    SEQ            BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    ATTRIBUTE_ID   VARCHAR(18)  DEFAULT NULL,
    ATTRIBUTE_NAME VARCHAR(255) DEFAULT NULL,
    SOURCE_ID      VARCHAR(18)  DEFAULT NULL,
    SOURCE_NAME    VARCHAR(255) DEFAULT NULL,
    VALUE_ID       VARCHAR(18)  DEFAULT NULL,
    VALUE_NAME     VARCHAR(255) DEFAULT NULL,
    -- MRCM Attribute Range Snapshot의 attributeRule에서 추출한 카디널리티 (예: 0..*, 0..1)
    CARDINALITY    VARCHAR(20)  DEFAULT NULL,
    PRIMARY KEY (SEQ)
);

CREATE INDEX IDX_MRCM_S_ID      ON MRCM_CONSTRAINTS (SOURCE_ID);
CREATE INDEX IDX_MRCM_A_ID      ON MRCM_CONSTRAINTS (ATTRIBUTE_ID);
CREATE INDEX IDX_MRCM_V_ID      ON MRCM_CONSTRAINTS (VALUE_ID);
CREATE INDEX IDX_MRCM_S_ID_A_ID ON MRCM_CONSTRAINTS (SOURCE_ID, ATTRIBUTE_ID);
CREATE INDEX IDX_MRCM_A_ID_V_ID ON MRCM_CONSTRAINTS (ATTRIBUTE_ID, VALUE_ID);

-- -----------------------------------------------------------------------------
-- REFERENCESET
-- 국제 및 애드온 패키지의 모든 Reference Set 통합 저장 테이블
-- FIELD1~FIELD7은 Reference Set 유형에 따라 의미가 다름:
--   Association Refset:  FIELD1=targetComponentId
--   Extended Map Refset: FIELD1=mapGroup, FIELD2=mapPriority, FIELD3=mapRule,
--                        FIELD4=mapAdvice, FIELD5=mapTarget, FIELD6=correlationId, FIELD7=mapCategoryId
--   Simple Map Refset:   FIELD1=mapTarget
-- MySQL UNIQUE KEY UUID → PostgreSQL UNIQUE 제약
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS REFERENCESET;
CREATE TABLE REFERENCESET (
    SEQ                     BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    -- UUID 형식의 Reference Set 멤버 고유 식별자 (36자)
    REFERENCESET_ID         CHAR(36)      NOT NULL,
    EFFECTIVE_TIME          CHAR(8)       NOT NULL,
    ACTIVE                  SMALLINT      NOT NULL,
    MODULE_ID               VARCHAR(18)   NOT NULL,
    REFSET_ID               VARCHAR(18)   NOT NULL,
    REFERENCED_COMPONENT_ID VARCHAR(18)   NOT NULL,
    FIELD1                  TEXT          DEFAULT NULL,
    FIELD2                  TEXT          DEFAULT NULL,
    FIELD3                  TEXT          DEFAULT NULL,
    FIELD4                  TEXT          DEFAULT NULL,
    -- FIELD5/FIELD6: MRCM ECL 표현식이 수만 자에 달하므로 VARCHAR 한계 초과 → TEXT
    FIELD5                  TEXT          DEFAULT NULL,
    FIELD6                  TEXT          DEFAULT NULL,
    FIELD7                  TEXT          DEFAULT NULL,
    DATE_CREATED            CHAR(8)       DEFAULT NULL,
    PRIMARY KEY (SEQ),
    -- RF2 멤버 UUID는 배포판 내에서 유일해야 함
    UNIQUE (REFERENCESET_ID)
);

CREATE INDEX IDX_REFERENCESET_ETIME_R_ID         ON REFERENCESET (EFFECTIVE_TIME, REFERENCESET_ID);
CREATE INDEX IDX_REFERENCESET_R_ID_R_C_ID         ON REFERENCESET (REFSET_ID, REFERENCED_COMPONENT_ID);
CREATE INDEX IDX_REFERENCESET_R_ID_R_C_ID_ETIME   ON REFERENCESET (REFSET_ID, REFERENCED_COMPONENT_ID, EFFECTIVE_TIME);
CREATE INDEX IDX_REFERENCESET_R_C_ID_R_ID_ETIME   ON REFERENCESET (REFERENCED_COMPONENT_ID, REFSET_ID, EFFECTIVE_TIME);

-- -----------------------------------------------------------------------------
-- REFERENCESET_ACTIVE
-- REFERENCESET(원본 RF2 전체 이력)에서 각 refset 항목의 최신 활성(active=1) 행만 추출한
-- 비정규화 조회 테이블. FIELD1~7 의 ID/VALUE 쌍으로 refset 유형별 추가 속성 저장.
-- MySQL DDL 변환 사항:
--   tinyint(1)  → SMALLINT
--   KEY ...     → 테이블 밖 CREATE INDEX
--   FULLTEXT    → PostgreSQL GIN 인덱스로 대체 (필요 시 활성화)
--   ENGINE/CHARSET 절 제거
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS REFERENCESET_ACTIVE;
CREATE TABLE REFERENCESET_ACTIVE (
    VERSION                     CHAR(12)      NOT NULL,
    UUID                        CHAR(36)      NOT NULL,
    EFFECTIVE_TIME              CHAR(8)       NOT NULL,
    MODULE_ID                   VARCHAR(18)   NOT NULL,
    MODULE_NAME                 VARCHAR(512)  NOT NULL,
    REFSET_ID                   VARCHAR(18)   NOT NULL,
    REFSET_NAME                 VARCHAR(512)  NOT NULL,
    REFERENCED_COMPONENT_ID     VARCHAR(18)   NOT NULL,
    REFERENCED_COMPONENT_ACTIVE SMALLINT      NOT NULL,
    REFERENCED_COMPONENT_NAME   VARCHAR(512)  NOT NULL,
    FIELD1_ID                   VARCHAR(18)   DEFAULT NULL,
    FIELD1_VALUE                VARCHAR(2047) DEFAULT NULL,
    FIELD2_ID                   VARCHAR(18)   DEFAULT NULL,
    FIELD2_VALUE                VARCHAR(550)  DEFAULT NULL,
    FIELD3_ID                   VARCHAR(18)   DEFAULT NULL,
    FIELD3_VALUE                VARCHAR(512)  DEFAULT NULL,
    FIELD4_ID                   VARCHAR(18)   DEFAULT NULL,
    FIELD4_VALUE                VARCHAR(512)  DEFAULT NULL,
    FIELD5_ID                   VARCHAR(18)   DEFAULT NULL,
    FIELD5_VALUE                VARCHAR(6200) DEFAULT NULL,
    FIELD6_ID                   VARCHAR(18)   DEFAULT NULL,
    FIELD6_VALUE                VARCHAR(6200) DEFAULT NULL,
    FIELD7_ID                   VARCHAR(18)   DEFAULT NULL,
    FIELD7_VALUE                VARCHAR(512)  DEFAULT NULL,
    DATE_CREATED                CHAR(8)       DEFAULT NULL,
    PRIMARY KEY (VERSION, UUID)
);
CREATE INDEX IDX_REFSET_ACTIVE_EU          ON REFERENCESET_ACTIVE (EFFECTIVE_TIME, UUID);
CREATE INDEX IDX_REFSET_ACITVE_URCID       ON REFERENCESET_ACTIVE (UUID, REFERENCED_COMPONENT_ID);
CREATE INDEX IDX_REFSET_ACTIVE_URCUDE      ON REFERENCESET_ACTIVE (UUID, REFERENCED_COMPONENT_ID, EFFECTIVE_TIME);
CREATE INDEX IDX_REFSET_ACITVE_URCIDF1AE   ON REFERENCESET_ACTIVE (UUID, REFERENCED_COMPONENT_ID, FIELD1_ID, REFERENCED_COMPONENT_ACTIVE, EFFECTIVE_TIME);
CREATE INDEX IDX_REFSET_ACTIVE_REFSET      ON REFERENCESET_ACTIVE (REFSET_ID);
CREATE INDEX IDX_REFSET_ACTIVE_F1          ON REFERENCESET_ACTIVE (FIELD1_ID);
CREATE INDEX IDX_REFSET_ACTIVE_F2          ON REFERENCESET_ACTIVE (FIELD2_ID);
CREATE INDEX IDX_REFSET_ACTIVE_F3          ON REFERENCESET_ACTIVE (FIELD3_ID);
CREATE INDEX IDX_REFSET_ACTIVE_F4          ON REFERENCESET_ACTIVE (FIELD4_ID);
CREATE INDEX IDX_REFSET_ACTIVE_F5          ON REFERENCESET_ACTIVE (FIELD5_ID);
CREATE INDEX IDX_REFSET_ACTIVE_F6          ON REFERENCESET_ACTIVE (FIELD6_ID);
CREATE INDEX IDX_REFSET_ACTIVE_F7          ON REFERENCESET_ACTIVE (FIELD7_ID);
-- FULLTEXT 검색이 필요한 경우 아래 주석 해제 (pg_trgm 확장 필요)
-- CREATE INDEX INEX_REFSET_RCNAME ON REFERENCESET_ACTIVE USING gin(REFERENCED_COMPONENT_NAME gin_trgm_ops);

-- -----------------------------------------------------------------------------
-- USER_REFERENCESET
-- 사용자 정의 Reference Set 저장 테이블 (Concept/Description 편집기에서 생성)
-- INCLUDE_SUBTYPES: 1이면 하위 개념 포함 조회
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS USER_REFERENCESET;
CREATE TABLE USER_REFERENCESET (
    SEQ                     BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    REFERENCESET_ID         CHAR(36)      NOT NULL,
    EFFECTIVE_TIME          CHAR(8)       NOT NULL,
    ACTIVE                  SMALLINT      NOT NULL,
    MODULE_ID               VARCHAR(18)   NOT NULL,
    REFSET_ID               VARCHAR(18)   NOT NULL,
    REFERENCED_COMPONENT_ID VARCHAR(18)   NOT NULL,
    FIELD1                  VARCHAR(511)  DEFAULT NULL,
    FIELD2                  VARCHAR(255)  DEFAULT NULL,
    FIELD3                  VARCHAR(255)  DEFAULT NULL,
    FIELD4                  VARCHAR(255)  DEFAULT NULL,
    FIELD5                  VARCHAR(255)  DEFAULT NULL,
    FIELD6                  VARCHAR(255)  DEFAULT NULL,
    FIELD7                  VARCHAR(255)  DEFAULT NULL,
    DATE_CREATED            CHAR(8)       DEFAULT NULL,
    INCLUDE_SUBTYPES        SMALLINT      DEFAULT NULL,
    CONCEPT_ID              VARCHAR(18)   DEFAULT NULL,
    TYPE                    VARCHAR(45)   DEFAULT NULL,
    PRIMARY KEY (SEQ)
);

-- -----------------------------------------------------------------------------
-- SCTID
-- SNOMED CT Extension ID 발급 이력 테이블 (Concept/Description 편집기 전용)
-- SEQ가 Extension item identifier로 직접 사용되므로 GENERATED BY DEFAULT 사용
-- CPNT_TYPE: 0=Concept, 1=Description, 2=Relationship (Partition Identifier)
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS SCTID;
CREATE TABLE SCTID (
    SEQ         INTEGER GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    CPNT_TYPE   INTEGER   NOT NULL,
    -- MySQL DEFAULT CURRENT_TIMESTAMP → PostgreSQL 동일하게 지원
    CREATE_DATE TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (SEQ)
);

-- -----------------------------------------------------------------------------
-- TC (Transitive Closure / Hierarchy)
-- SNOMED CT IS-A 계층의 전이적 폐쇄(Transitive Closure) 테이블
-- TransitiveClosureGeneratorFromInferred.sh + TransitiveClosureGenerator.java 변환
--
-- 각 행은 IS-A 관계의 직접 부모-자식 쌍 하나를 나타낸다.
-- 다중 부모(multiple inheritance) 개념은 부모마다 별도 행으로 존재.
-- PATH: 루트(138875005)에서 PARENT_ID까지 '~' 구분 경로 (예: 138875005~A~B)
-- DEPTH: 루트 기준 깊이 (루트=0, 루트 직계자녀=1)
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS TC;

-- -----------------------------------------------------------------------------
-- UMLS_SYNONYM
-- UMLS 기반 동의어 목록 (map_index/UMLS_SYNONYM/syn.txt)
-- syn.txt 형식: canonical,syn1,syn2,... (쉼표 구분, 언더스코어 공백 대체)
-- 검색 시 동의어 확장에 사용 (ES stop_synonym_analyzer 대체)
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS UMLS_SYNONYM;
CREATE TABLE UMLS_SYNONYM (
    ID        BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    CANONICAL VARCHAR(512) NOT NULL,
    SYNONYM   VARCHAR(512) NOT NULL,
    PRIMARY KEY (ID)
);
CREATE INDEX IDX_UMLS_SYN_CANONICAL ON UMLS_SYNONYM (LOWER(CANONICAL));
CREATE INDEX IDX_UMLS_SYN_SYNONYM   ON UMLS_SYNONYM (LOWER(SYNONYM));

-- -----------------------------------------------------------------------------
-- UMLS_SYNONYM_PHRASE
-- 다중 단어 구문 → 언더스코어 정규형 매핑 (map_index/UMLS_SYNONYM/syn_ph.txt)
-- syn_ph.txt 형식: "phrase with spaces => canonical_underscore_form"
-- 검색어 정규화 시 구문을 canonical로 변환한 후 UMLS_SYNONYM 조회
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS UMLS_SYNONYM_PHRASE;
CREATE TABLE UMLS_SYNONYM_PHRASE (
    ID        BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    PHRASE    VARCHAR(512) NOT NULL,
    CANONICAL VARCHAR(512) NOT NULL,
    PRIMARY KEY (ID)
);
CREATE INDEX IDX_UMLS_SYN_PH_PHRASE ON UMLS_SYNONYM_PHRASE (LOWER(PHRASE));
CREATE TABLE TC (
    SEQ               BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    CONCEPT_ID        VARCHAR(18)  NOT NULL,
    -- MySQL VARCHAR(255) → 512 (FSN은 255자 초과 가능)
    TERM              VARCHAR(512) NOT NULL,
    PARENT_ID         VARCHAR(18)  NOT NULL,
    CHILDREN_COUNT    INTEGER      DEFAULT 0,
    DESCENDANT_COUNT  INTEGER      DEFAULT 0,
    DEPTH             INTEGER      DEFAULT 0,
    -- MySQL VARCHAR(300) → TEXT (깊은 계층에서 경로 길이 초과 방지)
    PATH              TEXT         NOT NULL,
    DATE_CREATED      CHAR(8)      DEFAULT NULL,
    PRIMARY KEY (SEQ)
);

CREATE INDEX IDX_TC_C_ID ON TC (CONCEPT_ID);
CREATE INDEX IDX_TC_P_ID ON TC (PARENT_ID);
-- TEXT 컬럼은 직접 인덱스 불가 → 앞 300자에만 인덱스 (MySQL KEY IDX_TC_PATH 대응)
CREATE INDEX IDX_TC_PATH ON TC ((LEFT(PATH, 300)));

-- -----------------------------------------------------------------------------
-- SCHEME
-- -----------------------------------------------------------------------------
-- SEARCH_INDEX
-- Elasticsearch(v2.x) + Logstash + startup.sh 를 대체하는 PostgreSQL 내장 검색 인덱스.
-- CONCEPT + DESCRIPTION + REFERENCESET(US English) + MRCM_CONSTRAINTS 를 결합한
-- 비정규화 검색 뷰 테이블. pg_trgm GIN 인덱스로 자동완성·유사도 검색 지원.
--
-- ES 매핑 필드 대응:
--   conceptId               → CONCEPT_ID
--   descriptionId           → DESCRIPTION_ID
--   componentEffectiveTime  → COMPONENT_EFFECTIVE_TIME
--   componentActive         → COMPONENT_ACTIVE  (concept AND description 모두 active=1)
--   term                    → TERM  (GIN trgm 인덱스)
--   semanticTag             → SEMANTIC_TAG  (FSN 마지막 괄호 내용)
--   fsn                     → FSN
--   primitive               → PRIMITIVE  (definition_status_id=900000000000074008)
--   type                    → TYPE  (1=FSN, 3=Synonym, 4=Definition)
--   acceptabilityId         → ACCEPTABILITY_ID  (US English refset FIELD1)
--   mrcmAttrs               → MRCM_ATTRS  ('+' 구분 attribute_id 목록)
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS SEARCH_INDEX;
CREATE TABLE SEARCH_INDEX (
    SEQ                        BIGINT       GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    CONCEPT_ID                 VARCHAR(18)  NOT NULL,
    DESCRIPTION_ID             VARCHAR(18)  NOT NULL,
    COMPONENT_EFFECTIVE_TIME   CHAR(8)      NOT NULL,
    CONCEPT_EFFECTIVE_TIME     CHAR(8)      NOT NULL,
    DESCRIPTION_EFFECTIVE_TIME CHAR(8)      NOT NULL,
    COMPONENT_ACTIVE           SMALLINT     NOT NULL DEFAULT 0,
    CONCEPT_ACTIVE             SMALLINT     NOT NULL DEFAULT 0,
    DESCRIPTION_ACTIVE         SMALLINT     NOT NULL DEFAULT 0,
    TERM                       VARCHAR(4096) NOT NULL,
    SEMANTIC_TAG               VARCHAR(512) NOT NULL DEFAULT '',
    FSN                        VARCHAR(512) NOT NULL DEFAULT '',
    PRIMITIVE                  SMALLINT     NOT NULL DEFAULT 0,
    TYPE                       SMALLINT     NOT NULL DEFAULT 0,
    ACCEPTABILITY_ID           VARCHAR(18)  DEFAULT NULL,
    TERM_LENGTH                INTEGER      NOT NULL DEFAULT 0,
    LANG                       VARCHAR(2)   NOT NULL DEFAULT 'en',
    MRCM_ATTRS                 TEXT         NOT NULL DEFAULT '',
    PRIMARY KEY (SEQ)
);
CREATE INDEX IDX_SRCH_C_ID      ON SEARCH_INDEX (CONCEPT_ID);
CREATE INDEX IDX_SRCH_D_ID      ON SEARCH_INDEX (DESCRIPTION_ID);
CREATE INDEX IDX_SRCH_ACTIVE    ON SEARCH_INDEX (COMPONENT_ACTIVE, CONCEPT_ACTIVE, DESCRIPTION_ACTIVE);
CREATE INDEX IDX_SRCH_TYPE      ON SEARCH_INDEX (TYPE);
CREATE INDEX IDX_SRCH_LANG      ON SEARCH_INDEX (LANG);
-- 유사도·접두어 검색: pg_trgm GIN (LIKE '%word%', similarity())
CREATE INDEX IDX_SRCH_TERM_TRGM ON SEARCH_INDEX USING gin (TERM gin_trgm_ops);
-- 전문 검색: tsvector GIN (to_tsvector @@ plainto_tsquery)
CREATE INDEX IDX_SRCH_TERM_FTS  ON SEARCH_INDEX USING gin (to_tsvector('english', TERM));

-- 적재된 SNOMED CT 배포판 메타데이터 저장 테이블
-- AUTHORITY: 배포 기관 (예: SNOMED International)
-- DATE: 배포 기준일 (YYYYMMDD)
-- -----------------------------------------------------------------------------
DROP TABLE IF EXISTS SCHEME;
CREATE TABLE SCHEME (
    ID        VARCHAR(45) NOT NULL,
    NAME      VARCHAR(45) NOT NULL,
    EDITION   VARCHAR(45) NOT NULL,
    VERSION   VARCHAR(10) NOT NULL,
    AUTHORITY VARCHAR(45) NOT NULL,
    DATE      VARCHAR(10) NOT NULL,
    PRIMARY KEY (ID)
);

-- =============================================================================
-- LOINC Schema
-- MySQL DDL → PostgreSQL 변환
-- =============================================================================

CREATE SCHEMA IF NOT EXISTS loinc;

-- LOINC
DROP TABLE IF EXISTS loinc.LOINC CASCADE;
CREATE TABLE loinc.LOINC (
    CODE                        VARCHAR(10)  NOT NULL,
    COMPONENT                   VARCHAR(255) DEFAULT NULL,
    PROPERTY                    VARCHAR(30)  DEFAULT NULL,
    TIME_ASPECT                 VARCHAR(15)  DEFAULT NULL,
    SYSTEM                      VARCHAR(100) DEFAULT NULL,
    SCALE_TYPE                  VARCHAR(30)  DEFAULT NULL,
    METHOD_TYPE                 VARCHAR(50)  DEFAULT NULL,
    CLASS_NAME                  VARCHAR(20)  DEFAULT NULL,
    LAST_CHANGED_VERSION        VARCHAR(10)  DEFAULT NULL,
    CHANGE_TYPE                 VARCHAR(3)   DEFAULT NULL,
    DEFINITION_DESCRIPTION      TEXT,
    STATUS                      VARCHAR(11)  DEFAULT NULL,
    CONSUMER_NAME               VARCHAR(255) DEFAULT NULL,
    CLASS_TYPE                  INTEGER      DEFAULT NULL,
    FORMULA                     TEXT,
    EXAMPLE_ANSWERS             TEXT,
    SURVEY_QUEST_TEXT           TEXT,
    SURVEY_QUEST_SRC            VARCHAR(50)  DEFAULT NULL,
    UNITS_REQUIRED              VARCHAR(1)   DEFAULT NULL,
    SUBMITTED_UNITS             VARCHAR(30)  DEFAULT NULL,
    RELATED_NAMES2              TEXT,
    SHORT_NAME                  VARCHAR(40)  DEFAULT NULL,
    ORDER_OBS                   VARCHAR(15)  DEFAULT NULL,
    CDISC_COMMON_TESTS          VARCHAR(1)   DEFAULT NULL,
    HL7_FIELD_SUBFIELD_ID       VARCHAR(50)  DEFAULT NULL,
    EXTERNAL_COPYRIGHT_NOTICE   TEXT,
    EXAMPLE_UNITS               VARCHAR(255) DEFAULT NULL,
    LONG_COMMON_NAME            VARCHAR(255) DEFAULT NULL,
    UNITS_AND_RANGE             TEXT,
    EXAMPLE_UCUM_UNITS          VARCHAR(255) DEFAULT NULL,
    EXAMPLE_SI_UCUM_UNITS       VARCHAR(255) DEFAULT NULL,
    STATUS_REASON               VARCHAR(9)   DEFAULT NULL,
    STATUS_TEXT                 TEXT,
    CHANGE_REASON_PUBLIC        TEXT,
    COMMON_TEST_RANK            INTEGER      DEFAULT NULL,
    COMMON_ORDER_RANK           INTEGER      DEFAULT NULL,
    COMMON_SI_TEST_RANK         INTEGER      DEFAULT NULL,
    HL7_ATTACHMENT_STRUCTURE    VARCHAR(15)  DEFAULT NULL,
    EXTERNAL_COPYRIGHT_LINK     VARCHAR(255) DEFAULT NULL,
    PANEL_TYPE                  VARCHAR(255) DEFAULT NULL,
    ASK_AT_ORDER_ENTRY          VARCHAR(255) DEFAULT NULL,
    ASSOCIATED_OBSERVATIONS     VARCHAR(50)  DEFAULT NULL,
    FIRST_RELEASED_VERSION      VARCHAR(255) DEFAULT NULL,
    VALID_HL7_ATTACHMENT_REQUEST VARCHAR(255) DEFAULT NULL,
    DISPLAY_NAME                VARCHAR(255) DEFAULT NULL,
    PRIMARY KEY (CODE)
);

-- MAP_TO
DROP TABLE IF EXISTS loinc.MAP_TO CASCADE;
CREATE TABLE loinc.MAP_TO (
