);
CREATE INDEX IDX_LNC_HTMP_CODE       ON loinc.HIERARCHY_TMP (CODE);
CREATE INDEX IDX_LNC_HTMP_PARENT     ON loinc.HIERARCHY_TMP (PARENT);
CREATE INDEX IDX_LNC_HTMP_PATH       ON loinc.HIERARCHY_TMP (PATH);

-- HIERARCHY_LG
DROP TABLE IF EXISTS loinc.HIERARCHY_LG CASCADE;
CREATE TABLE loinc.HIERARCHY_LG (
    SEQ              BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    CHILDREN_COUNT   INTEGER DEFAULT 0,
    CODE             VARCHAR(50)  DEFAULT NULL,
    DESCENDANT_COUNT INTEGER DEFAULT 0,
    NAME             VARCHAR(255) DEFAULT NULL,
    PARENT           VARCHAR(255) DEFAULT NULL,
    PATH             VARCHAR(255) DEFAULT NULL,
    PREFERRED_NAME   TEXT,
