CREATE INDEX IDX_LNC_HLG_DESCENDANT ON loinc.HIERARCHY_LG (DESCENDANT_COUNT);

-- LINGUISTIC_VARIANT
DROP TABLE IF EXISTS loinc.LINGUISTIC_VARIANT CASCADE;
CREATE TABLE loinc.LINGUISTIC_VARIANT (
    SEQ              BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
    CODE             VARCHAR(10)  DEFAULT NULL,
    COMPONENT        VARCHAR(255) DEFAULT NULL,
