    PARENT_NAME                  VARCHAR(255) DEFAULT NULL,
    ID                           VARCHAR(11)  DEFAULT NULL,
    SEQUENCE                     INTEGER      DEFAULT NULL,
    CODE                         VARCHAR(10)  DEFAULT NULL,
    NAME                         VARCHAR(255) DEFAULT NULL,
    DISPLAY_NAME_FOR_FORM        VARCHAR(255) DEFAULT NULL,
    OBSERVATION_REQUIRED_IN_PANEL VARCHAR(255) DEFAULT NULL,
    OBSERVATION_ID_IN_FORM       VARCHAR(10)  DEFAULT NULL,
    SKIP_LOGIC_HELP_TEXT         VARCHAR(255) DEFAULT NULL,
