    ENTRY_TYPE                   VARCHAR(10)  DEFAULT NULL,
    DATA_TYPE_IN_FORM            VARCHAR(10)  DEFAULT NULL,
    DATA_TYPE_SOURCE             VARCHAR(255) DEFAULT NULL,
    ANSWER_SEQUENCE_OVERRIDE     VARCHAR(255) DEFAULT NULL,
    CONDITION_FOR_INCLUSION      VARCHAR(255) DEFAULT NULL,
    ALLOWABLE_ALTERNATIVE        VARCHAR(255) DEFAULT NULL,
    OBSERVATION_CATEGORY         VARCHAR(20)  DEFAULT NULL,
